const dash = $('Load Dashboard').first().json.dashboard;
const events = $input.first().json.events || [];
const sevColor = { critical: '#e74c3c', high: '#e67e22', medium: '#f1c40f', low: '#3498db', info: '#7f8c8d' };
const eventRows = events.map(e => '<tr>' +
  '<td><span style=\"background:' + (sevColor[e.severity] || '#95a5a6') + ';color:white;padding:3px 8px;border-radius:12px;font-size:11px\">' + (e.severity || '?').toUpperCase() + '</span></td>' +
  '<td>' + e.event_type + '</td>' +
  '<td>' + (e.endpoint || '—') + '</td>' +
  '<td style=\"font-size:11px\">' + (e.source_ip || '—') + '</td>' +
  '<td style=\"font-size:11px\">' + (e.description || '—') + '</td>' +
  '<td style=\"font-size:10px;color:#7f8c8d\">' + (e.occurred_at ? e.occurred_at.substring(0,16) : '') + '</td>' +
  '</tr>').join('');
const kpi = (label, val, danger) => '<tr><td style=\"padding:6px 12px\">' + label + '</td><td style=\"padding:6px 12px;text-align:right' + (danger ? ';background:#ffe0e0' : '') + '\"><b>' + (val !== null && val !== undefined ? val : '-') + '</b></td></tr>';
const html = `<div style=\"font-family:Arial,sans-serif;max-width:760px;margin:0 auto\">
<h2 style=\"color:#2c3e50\">Security Dashboard — ArquitAI</h2>
<p style=\"color:#7f8c8d\">Resumen semanal de eventos y estado de seguridad. Generado: ${new Date().toLocaleString('es-ES', {timeZone:'Europe/Madrid'})}</p>

<h3>KPIs estado actual</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Critical events sin resolver', dash.critical_unresolved, dash.critical_unresolved > 0)}
${kpi('Medium events sin resolver', dash.medium_unresolved, dash.medium_unresolved > 5)}
${kpi('Eventos ult. 24h', dash.events_last_24h)}
${kpi('Auth failures 24h', dash.auth_failures_24h, dash.auth_failures_24h > 5)}
${kpi('Rate limit hits 24h', dash.rate_limit_hits_24h, dash.rate_limit_hits_24h > 0)}
${kpi('Injection attempts 24h', dash.injection_attempts_24h, dash.injection_attempts_24h > 0)}
${kpi('Accesos denegados 24h', dash.denied_24h)}
${kpi('IPs unicas 24h', dash.unique_ips_24h)}
</table>

<h3>Tokens y consents</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Tokens activos', dash.active_tokens)}
${kpi('Tokens stale (>60d sin uso)', dash.stale_tokens, dash.stale_tokens > 0)}
${kpi('Tokens expiran en 7d', dash.expiring_soon, dash.expiring_soon > 0)}
${kpi('Consents activos', dash.active_consents)}
${kpi('Clientes sin consent registrado', dash.clients_without_consent, dash.clients_without_consent > 0)}
</table>

<h3>RGPD</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Solicitudes pendientes', dash.gdpr_pending, dash.gdpr_pending > 0)}
${kpi('Cerca de deadline 1 mes', dash.gdpr_near_deadline, dash.gdpr_near_deadline > 0)}
</table>

<h3>Higiene</h3>
<table style=\"border-collapse:collapse;width:100%\">
${kpi('Ultima rotacion de clave', dash.last_key_rotation || 'nunca')}
${kpi('Ultimo pen-test', dash.last_pen_test || 'nunca')}
</table>

${eventRows ? `<h3>Eventos recientes 7d</h3><table border=\"1\" cellpadding=\"5\" style=\"border-collapse:collapse;font-size:12px;width:100%\"><thead><tr style=\"background:#f3f4f6\"><th>Sev</th><th>Tipo</th><th>Endpoint</th><th>IP</th><th>Descripcion</th><th>Cuando</th></tr></thead><tbody>${eventRows}</tbody></table>` : '<p style=\"color:#27ae60\">✅ Sin eventos de seguridad en la ultima semana.</p>'}

<p style=\"font-size:11px;color:#95a5a6;margin-top:24px\">Endpoint API equivalente: <code>SELECT * FROM security_dashboard;</code></p>
</div>`;
const totalAlerts = (dash.critical_unresolved || 0) + (dash.injection_attempts_24h || 0) + (dash.gdpr_near_deadline || 0) + (dash.stale_tokens || 0);
return [{ json: { html_body: html, subject: 'ArquitAI Security — KPIs semanales' + (totalAlerts > 0 ? ' (' + totalAlerts + ' alertas)' : '') } }];

